const API='https://tyzfznwvjzmudxtcbbaf.supabase.co',KEY='sb_publishable_Pg54r3i2MT5snGLhT8EQbQ_snr-KfVC',AUTH_DOMAIN='auth.harmonylembrancinhas.com.br';
