async function json(r){let b=await r.json().catch(()=>({}));if(!r.ok)throw Error(b.message||b.msg||b.error_description||b.error||'Não foi possível concluir.');return b}
let sessionRefreshPromise=null;
async function refreshSession(){if(sessionRefreshPromise)return sessionRefreshPromise;sessionRefreshPromise=(async()=>{if(!S.session?.refresh_token)throw Error('Sua sessão terminou. Entre novamente.');let d=await json(await fetch(API+'/auth/v1/token?grant_type=refresh_token',{method:'POST',headers:{apikey:KEY,'Content-Type':'application/json'},body:JSON.stringify({refresh_token:S.session.refresh_token})}));d.expires_at=Math.floor(Date.now()/1000)+d.expires_in;localStorage.setItem('harmony.session',JSON.stringify(d));S.session=d;return d})().finally(()=>sessionRefreshPromise=null);return sessionRefreshPromise}
async function ensureSession(){if(!S.session?.access_token)throw Error('Sua sessão terminou. Entre novamente.');if(!S.session.expires_at||S.session.expires_at<Math.floor(Date.now()/1000)+90)await refreshSession()}
