function renderLogin(){S.view='home';$('#app').innerHTML=`<main class="login"><section class="story"><p class="eyebrow">HARMONY STORE OFICIAL</p><h1>Cuidado artesanal,<br><em>gestão impecável.</em></h1><p>Materiais, solicitações e entregas reunidos em um ambiente seguro, criado para a rotina da nossa produção.</p><div class="artisan"><i>✦</i><span><b>Feito para a nossa essência</b><small>Organização leve, delicada e eficiente.</small></span></div></section><section class="login-panel"><div class="login-box"><img src="logo.jpg" alt="Harmony Store Oficial"><p class="eyebrow">ACESSO RESTRITO</p><h2>Bem-vinda</h2><p>Use o login criado pela administradora.</p><form id="loginForm"><label>Login<input name="user" placeholder="seu.login" autocomplete="username" required></label><label>Senha<div class="password"><input name="password" type="password" autocomplete="current-password" required><button type="button" id="showPass">Ver</button></div></label><div id="loginError"></div><button class="primary">Entrar no sistema</button></form><small class="safe">Seus dados são protegidos. Nunca compartilhe sua senha.</small></div></section></main>`;$('#showPass').onclick=()=>{let i=$('[name=password]');i.type=i.type==='password'?'text':'password';$('#showPass').textContent=i.type==='password'?'Ver':'Ocultar'};$('#loginForm').onsubmit=async e=>{e.preventDefault();let b=e.submitter;b.disabled=true;try{await login(e.target.user.value,e.target.password.value);renderApp()}catch(x){$('#loginError').innerHTML=`<div class="error">${esc(/invalid login/i.test(x.message)?'Login ou senha incorretos.':x.message)}</div>`;b.disabled=false}}}
